// Automated Accessibility & Email Quality Tests
const html = query;

if (!html || html.trim().length < 50) {
  return 'ERROR: No valid HTML provided. Please pass the complete HTML email code to this tool.';
}

const issues = [];
const warnings = [];
const passed = [];

// === POUR: Robust - Language attribute ===
if (/<html[^>]*lang\s*=/i.test(html)) {
  passed.push('HTML lang attribute present');
} else {
  issues.push('Missing lang attribute on <html> tag');
}

// === POUR: Understandable - Heading hierarchy ===
const headingMatches = [...html.matchAll(/<h([1-6])[^>]*>/gi)];
const headingLevels = headingMatches.map(m => parseInt(m[1]));
let headingOk = true;
for (let i = 1; i < headingLevels.length; i++) {
  if (headingLevels[i] > headingLevels[i - 1] + 1) {
    issues.push('Heading hierarchy skip: h' + headingLevels[i - 1] + ' jumps to h' + headingLevels[i]);
    headingOk = false;
  }
}
if (headingOk && headingLevels.length > 0) passed.push('Heading hierarchy correct (' + headingLevels.length + ' headings)');
if (headingLevels.length === 0) warnings.push('No headings found - consider adding heading structure');

// === POUR: Perceivable - Image alt text ===
const imgs = html.match(/<img[^>]*>/gi) || [];
let missingAlt = 0;
for (const img of imgs) {
  if (!/alt\s*=/i.test(img)) missingAlt++;
}
if (missingAlt > 0) issues.push(missingAlt + ' image(s) missing alt attribute');
else if (imgs.length > 0) passed.push('All ' + imgs.length + ' images have alt attributes');

// === Dark Mode ===
if (/@media[^{]*prefers-color-scheme\s*:\s*dark/i.test(html)) {
  passed.push('Dark mode @media query present');
} else {
  issues.push('No @media (prefers-color-scheme: dark) found');
}
if (/color-scheme/i.test(html)) {
  passed.push('color-scheme meta tag present');
} else {
  warnings.push('Missing color-scheme meta tag');
}
if (/data-og[sc][cb]/i.test(html)) {
  passed.push('Outlook dark mode selectors present');
} else {
  warnings.push('Missing Outlook dark mode selectors ([data-ogsc]/[data-ogsb])');
}

// === POUR: Robust - Layout table roles ===
const tables = html.match(/<table[^>]*>/gi) || [];
let tablesWithoutRole = 0;
for (const table of tables) {
  if (!/role\s*=\s*["']presentation["']/i.test(table)) tablesWithoutRole++;
}
if (tablesWithoutRole > 0) warnings.push(tablesWithoutRole + ' table(s) missing role="presentation"');
else if (tables.length > 0) passed.push('All ' + tables.length + ' tables have role="presentation"');

// === POUR: Perceivable - Font sizes ===
const fontSizes = [...html.matchAll(/font-size\s*:\s*(\d+(?:\.\d+)?)\s*px/gi)];
let smallFonts = 0;
for (const fs of fontSizes) {
  if (parseFloat(fs[1]) < 14) smallFonts++;
}
if (smallFonts > 0) warnings.push(smallFonts + ' font-size declaration(s) below 14px minimum');
else if (fontSizes.length > 0) passed.push('All font sizes meet 14px minimum');

// === POUR: Understandable - List markup ===
const bulletChars = html.match(/[\u2022\u25CF\u25E6\u25AA\u25AB\u2023\u2043]/g) || [];
const hasListTags = /<[uo]l[^>]*>/i.test(html);
if (bulletChars.length > 0 && !hasListTags) {
  issues.push('Manual bullet characters found (' + bulletChars.length + ') without proper <ul>/<ol> markup');
} else {
  passed.push('No manual bullet characters detected');
}

// === POUR: Operable - Link text quality ===
const links = [...html.matchAll(/<a[^>]*>([^<]*)<\/a>/gi)];
const badTexts = ['click here', 'read more', 'learn more', 'here', 'link', 'more', 'click'];
let badLinks = [];
for (const link of links) {
  const text = link[1].trim().toLowerCase();
  if (badTexts.includes(text)) badLinks.push('"' + link[1].trim() + '"');
}
if (badLinks.length > 0) warnings.push('Non-descriptive link text found: ' + badLinks.join(', '));
else if (links.length > 0) passed.push('All ' + links.length + ' links have descriptive text');

// === Email essentials ===
if (/<!DOCTYPE html>/i.test(html)) passed.push('HTML5 DOCTYPE present');
else warnings.push('Missing HTML5 DOCTYPE');

if (/meta[^>]*charset/i.test(html)) passed.push('Meta charset present');
else warnings.push('Missing meta charset');

if (/meta[^>]*viewport/i.test(html)) passed.push('Meta viewport present');
else warnings.push('Missing meta viewport');

if (/max-width|width\s*:\s*600/i.test(html)) passed.push('Email width constraint detected');
else warnings.push('No 600px max-width detected - emails should be max 600px wide');

// === Build report ===
const status = issues.length === 0 ? 'ALL CHECKS PASSED' : 'ISSUES FOUND';
let report = '═══ ACCESSIBILITY & EMAIL TEST REPORT ═══\n\n';
report += 'Status: ' + status + '\n';
report += 'Passed: ' + passed.length + ' | Issues: ' + issues.length + ' | Warnings: ' + warnings.length + '\n\n';

if (passed.length > 0) {
  report += '✅ PASSED:\n' + passed.map(p => '  ✅ ' + p).join('\n') + '\n\n';
}
if (issues.length > 0) {
  report += '❌ ISSUES (must fix):\n' + issues.map(i => '  ❌ ' + i).join('\n') + '\n\n';
}
if (warnings.length > 0) {
  report += '⚠️ WARNINGS (should fix):\n' + warnings.map(w => '  ⚠️ ' + w).join('\n') + '\n\n';
}

return report;

// Package for Delivery
let input;
try {
  input = JSON.parse(query);
} catch(e) {
  return 'ERROR: Please pass a valid JSON string with fields: html, campaignName, proofEmail, jiraProject, brandNotes, testSummary';
}

const html = input.html || '';
const campaignName = input.campaignName || 'Untitled Campaign';
const proofEmail = input.proofEmail || 'not specified';
const jiraProject = input.jiraProject || 'not specified';
const brandNotes = input.brandNotes || 'No brand notes';
const testSummary = input.testSummary || 'No test summary';
const timestamp = new Date().toISOString().split('T')[0];

let output = '═══ DELIVERY PACKAGE READY ═══\n\n';
output += 'Campaign: ' + campaignName + '\n';
output += 'Date: ' + timestamp + '\n\n';

output += '── 1. PROOF EMAIL ──\n';
output += 'To: ' + proofEmail + '\n';
output += 'Subject: [Proof] ' + campaignName + ' - ' + timestamp + '\n';
output += 'Body: The final HTML email has been produced and tested. Please review and reply with approval or feedback.\n\n';

output += '── 2. JIRA TICKET ──\n';
output += 'Project: ' + jiraProject + '\n';
output += 'Type: Task\n';
output += 'Summary: [Email Build] ' + campaignName + ' - ' + timestamp + '\n';
output += 'Description: Campaign email produced via automated pipeline.\n';
output += 'Test Results: ' + testSummary + '\n';
output += 'Brand Notes: ' + brandNotes + '\n\n';

output += '── 3. MARTECH PUSH ──\n';
output += 'Campaign Name: ' + campaignName + '\n';
output += 'HTML Length: ' + html.length + ' characters\n';
output += 'Status: Ready for platform upload\n\n';

output += '── FINAL HTML ──\n';
output += 'The approved HTML (' + html.length + ' chars) is ready. Copy from the conversation above or from the last code block shown.\n\n';

output += 'To automate delivery, connect Send Email, HTTP Request (MarTech), and Jira nodes downstream of this agent in the n8n workflow editor.';

return output;
